{"content": ""use client"

import { useState } from "react"
import Link from "next/link"
import { Menu, X } from "lucide-react"
import content from "@/content/es.json"

export default function Header() {
  const [open, setOpen] = useState(false)
  const s = content.site
  const nav = [
    { label: "Inicio", href: "/" },
    { label: "Galería", href: "/#galeria" },
    { label: "FAQ", href: "/#faq" },
    { label: "Contacto", href: "/#contacto" },
  ]

  return (
    <header style={{ backgroundColor: "white", borderBottom: "1px solid #E5DEEC", position: "sticky", top: 0, zIndex: 50 }}>
      <div style={{ maxWidth: "1200px", margin: "0 auto", padding: "0 1rem", display: "flex", alignItems: "center", justifyContent: "space-between", height: "64px" }}>
        <Link href="/" style={{ fontWeight: 700, fontSize: "1.25rem", color: "#7C3AED", textDecoration: "none" }}>
          {s.name}
        </Link>

        <nav style={{ display: "none", gap: "1.5rem" }} className="md-flex">
          {nav.map((n, i) => (
            <Link key={i} href={n.href} style={{ color: "#6B7280", textDecoration: "none", fontSize: "0.875rem", fontWeight: 500 }}>
              {n.label}
            </Link>
          ))}
        </nav>

        <button onClick={() => setOpen(!open)} style={{ background: "none", border: "none", cursor: "pointer" }} className="md-hidden">
          {open ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {open && (
        <div style={{ padding: "1rem", backgroundColor: "white", borderTop: "1px solid #E5DEEC" }}>
          {nav.map((n, i) => (
            <Link key={i} href={n.href} onClick={() => setOpen(false)}
              style={{ display: "block", padding: "0.75rem 0", color: "#1A1A2E", textDecoration: "none", borderBottom: i < nav.length-1 ? "1px solid #F3E8FF" : "none" }}>
              {n.label}
            </Link>
          ))}
        </div>
      )}
    </header>
  )
}
